fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let mut count = 0;
    for i in 0..m {
        for j in 0..n {
            if grid[i][j] > 0 {
                let mut queue = VecDeque::new();
                queue.push_back((i, j));
                let mut sum_val = 0;
                while let Some((x, y)) = queue.pop_front() {
                    sum_val += grid[x][y];
                    grid[x][y] = 0;
                    let directions = [(-1, 0), (1, 0), (0, -1), (0, 1)];
                    for (dx, dy) in directions {
                        let nx = x as i64 + dx;
                        let ny = y as i64 + dy;
                        if nx >= 0 && nx < m as i64 && ny >= 0 && ny < n as i64 {
                            let nx_usize = nx as usize;
                            let ny_usize = ny as usize;
                            if grid[nx_usize][ny_usize] > 0 {
                                queue.push_back((nx_usize, ny_usize));
                            }
                        }
                    }
                }
                if sum_val % k == 0 {
                    count += 1;
                }
            }
        }
    }
    count
}
