                queue = deque()
                queue.append((i, j))
                sum_val = 0
                while queue:
                    x, y = queue.popleft()
                    sum_val += grid[x][y]
                    grid[x][y] = 0
                    for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
